SELECT shark_species
FROM shark_species
WHERE species_id IN (
    SELECT species_id
    FROM shark_encounters
);

SELECT outcome
FROM shark_encounters
WHERE reported_by = 'Marine Patrol';

SELECT shark_species
FROM shark_species
WHERE attacks = (
    SELECT MAX(attacks)
    FROM shark_species
);

SELECT shark_species
FROM shark_species
WHERE risk = (SELECT MAX(risk) FROM shark_species);

SELECT shark_species
FROM shark_species
WHERE risk = (SELECT MAX(risk) FROM shark_species);

SELECT shark_species, AVG(average_size_ft) AS average_size
FROM shark_species
GROUP BY shark_species;

